var e=[{id:`L2_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`여기야? 그 알렌이란 사람의 자택이라는 곳이?`,JPN:`アレンっていう人の自宅はここなんだよね？`,ENG:`So, is this it? This is that Allen guy's home?`,TWN:`就是這裡嗎？那個叫艾倫的人住的地方？`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`어, 응. 학생회장이 보내 준 주소대로라면 여기가 맞아.`,JPN:`うん、生徒会長が送ってくれた住所どおりならここで合ってるよ。`,ENG:`Yeah. At least according to the address Yen gave me.`,TWN:`嗯，學生會長傳給我的地址是這裡沒錯。`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`그렇지만 이걸 <color=#ffd34c>자택</color>이라고 부른다는 건 좀 어폐가 있어 보이네.`,JPN:`でもこれを<color=#ffd34c>自宅</color>と呼ぶのはかなり語弊がありそうだね。`,ENG:`Hmm... It's a bit of a stretch to call this place a <color=#ffd34c>home</color> though.`,TWN:`可是這裡要稱為<color=#ffd34c>住家</color>好像有點勉強。`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`여긴 숲이잖아. 그것도 엄청 넓은.`,JPN:`ここは森でしょう。しかも相当広い。`,ENG:`I mean, it's literally just a forest. And a huge one at that.`,TWN:`這裡不是森林嗎？而且還是很大一片的森林！`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`그러게. 대문 밖에서 봤을 때는 분명히 이렇게까지 넓어 보이진 않았는데…….`,JPN:`そうだね。門の外から見た時は、ここまで広くは見えなかったのに……`,ENG:`Agreed. It didn't seem this big from the gate though...`,TWN:`對啊，從大門口看感覺沒這麼大啊……`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_DESPAIR`}}}},{id:`L10_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`그 알렌이란 선생님, 카운터야?`,JPN:`そのアレンって先生はカウンターなの？`,ENG:`So, is this Allen Birmingham a Counter?`,TWN:`那個叫艾倫的老師是制裁者嗎？`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`언더그라운드 때도 방향 감각을 속여서 골탕 먹이는 용병을 만난 적 있거든.`,JPN:`アンダーグラウンド時代に相手の方向感覚を失わせて惑わす傭兵に会ったことがあるんだ。`,ENG:`Because back when I was in the Underground, I met a mercenary who could mess with your sense of direction.`,TWN:`我在地下世界時期也有遇過一位很會掩人耳目的傭兵。`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`그게……. 생각해 보니까 전술학 교수라는 소개 말고는 들은 적 없어.`,JPN:`それが……思い出してみたら戦術学の先生という紹介以外、他の情報は聞いていないんだ。`,ENG:`Well... Come to think of it, I never heard anything about him except that he teaches tactics at the Academy.`,TWN:`這個嘛……現在回想起來，好像只知道他是戰術學老師，其他都不太清楚。`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`흐흠. 얼굴 한 번 못 봤는데 알면 알수록 점점 더 수상해지네.`,JPN:`ふーん。まだ会ったことはないけど、知れば知るほど怪しい人だわ。`,ENG:`Hmm… Curiouser and curiouser… I haven't even met this guy yet and he already smells fishy to me.`,TWN:`嗯嗯，雖然沒看過他的臉，但越是認識他，就越覺得哪裡不對勁。`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`CUTSCEN_FOREST_LOOP`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NULL_NULL`,text:{KOREA:`방금 들었어?!`,JPN:`今の聞いた！？`,ENG:`Did you hear that just now?!`,TWN:`你有聽到嗎？！`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`BATTLE_NORMAL_02`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L18_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`그래. 침식파 반응도 확인했어.`,JPN:`うん、侵食波反応も確認した。`,ENG:`Yeah. I also detected a Corruption Ray response.`,TWN:`有，是侵蝕波的反應！`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`BATTLE_NORMAL_02`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`저쪽에서 누가 싸우고 있나 봐! 서두르자!`,JPN:`向こうで誰かが戦っているみたい！　急ごう！`,ENG:`Someone must be fighting over there! Let's hurry!`,TWN:`那邊有人在戰鬥！快去看看！`},stage:{bg:`COUNTERSIDE_FOREST`,bgm:`BATTLE_NORMAL_02`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOMINA_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};